class Solution:
    def numberOfStableArrays(self, zero: int, one: int, limit: int) -> int:
        MOD = 10**9 + 7

        # dp[z][o][last] = number of valid arrays with z zeros, o ones, ending with 'last' (0 or 1)
        dp = [[[0] * 2 for _ in range(one + 1)] for __ in range(zero + 1)]

        # Initialize base cases
        for z in range(zero + 1):
            for o in range(one + 1):
                if z == 0 and o == 0:
                    continue
                if z == 0:
                    dp[z][o][1] = 1
                elif o == 0:
                    dp[z][o][0] = 1
                else:
                    dp[z][o][0] = 1
                    dp[z][o][1] = 1

        # Fill the DP table
        for z in range(zero + 1):
            for o in range(one + 1):
                if z == 0 and o == 0:
                    continue
                if z == 0:
                    dp[z][o][1] = 1
                    continue
                if o == 0:
                    dp[z][o][0] = 1
                    continue

                # If last digit is 0
                if dp[z][o][0] > 0:
                    for l in range(1, limit + 1):
                        if z >= l:
                            dp[z][o][0] += dp[z - l][o][1]
                            dp[z][o][0] %= MOD
                # If last digit is 1
                if dp[z][o][1] > 0:
                    for l in range(1, limit + 1):
                        if o >= l:
                            dp[z][o][1] += dp[z][o - l][0]
                            dp[z][o][1] %= MOD

        return (dp[zero][one][0] + dp[zero][one][1]) % MOD
